def balanced(s):
    """
    Returns True if the parentheses in the string are balanced, False otherwise.

    :param s: The input string to check for balanced parentheses.
    :return: A boolean indicating whether the parentheses are balanced.
    """

    stack = []
    for char in s:
        if char == '(':
            # When an opening parenthesis is encountered, push it onto the stack.
            stack.append(char)
        elif char == ')':
            # If a closing parenthesis is encountered and the stack is empty, return False.
            if not stack:
                return False
            # Otherwise, pop the corresponding opening parenthesis from the stack.
            else:
                stack.pop()
    # An empty string is balanced, so we need to handle this edge case separately.
    if s == '':
        return True
    # If there are any remaining opening parentheses in the stack after processing the entire string, return False.
    elif stack:
        return False
    else:
        return True
